/* ================================================================
 * Transight Design System — Flex 유틸리티
 * 네이밍: flex-(direction)-(justify)-(align)
 * ================================================================ */

@layer utilities {
  /* 단순 정렬 */
  .flex-start {
    @apply flex items-start justify-start;
  }
  .flex-center {
    @apply flex items-center justify-center;
  }
  .flex-end {
    @apply flex items-end justify-end;
  }
  .flex-col-start {
    @apply flex flex-col items-start justify-start;
  }
  .flex-col-center {
    @apply flex flex-col items-center justify-center;
  }
  .flex-col-end {
    @apply flex flex-col items-end justify-end;
  }

  /* ── flex-row: justify-{kind}-align-{kind} ── */
  .flex-start-center {
    @apply flex items-center justify-start;
  }
  .flex-start-end {
    @apply flex items-end justify-start;
  }
  .flex-center-start {
    @apply flex items-start justify-center;
  }
  .flex-center-end {
    @apply flex items-end justify-center;
  }
  .flex-end-start {
    @apply flex items-start justify-end;
  }
  .flex-end-center {
    @apply flex items-center justify-end;
  }
  .flex-around-start {
    @apply flex items-start justify-around;
  }
  .flex-around-center {
    @apply flex items-center justify-around;
  }
  .flex-around-end {
    @apply flex items-end justify-around;
  }
  .flex-between-start {
    @apply flex items-start justify-between;
  }
  .flex-between-center {
    @apply flex items-center justify-between;
  }
  .flex-between-end {
    @apply flex items-end justify-between;
  }

  /* ── flex-col ── */
  .flex-col-start-center {
    @apply flex flex-col items-center justify-start;
  }
  .flex-col-start-end {
    @apply flex flex-col items-end justify-start;
  }
  .flex-col-center-start {
    @apply flex flex-col items-start justify-center;
  }
  .flex-col-center-end {
    @apply flex flex-col items-end justify-center;
  }
  .flex-col-end-start {
    @apply flex flex-col items-start justify-end;
  }
  .flex-col-end-center {
    @apply flex flex-col items-center justify-end;
  }
  .flex-col-around-start {
    @apply flex flex-col items-start justify-around;
  }
  .flex-col-around-center {
    @apply flex flex-col items-center justify-around;
  }
  .flex-col-around-end {
    @apply flex flex-col items-end justify-around;
  }
  .flex-col-between-start {
    @apply flex flex-col items-start justify-between;
  }
  .flex-col-between-center {
    @apply flex flex-col items-center justify-between;
  }
  .flex-col-between-end {
    @apply flex flex-col items-end justify-between;
  }
}
